document.addEventListener("click",function(e){let n=e.target.closest("#cookie-banner-link");if(!n||n.matches(`[href="${window.router?.["frontend.cookie.offcanvas"]}"]`))return;e.preventDefault();let o=document.querySelector("[data-cookie-permission]");if(!o){console.warn("Shopware cookie consent is not enabled on this sales channel.");return}let t=window.PluginManager.getPluginInstanceFromElement(o,"CookieConfiguration");if(t?.openOffCanvas){t.openOffCanvas();return}document.querySelector(".js-cookie-configuration-button button")?.click()});